namespace sv_61154eade5f549b8920385640ee84344.Models;

// Domain records (service contracts)
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate!.Value, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    padding: 1rem 0;
}

.step-connector {
    flex: 1;
    height: 2px;
    background-color: #dee2e6;
    margin: 0 0.25rem;
    max-width: 60px;
    transition: background-color 0.3s;
}

.step-connector.completed {
    background-color: #198754;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0.5rem;
    gap: 0.5rem;
    transition: opacity 0.3s;
}

.step-item.future {
    opacity: 0.4;
    cursor: not-allowed;
}

.step-item.completed:hover .step-circle {
    transform: scale(1.1);
}

.step-circle {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: white;
    color: #6c757d;
    transition: all 0.3s;
}

.step-item.current .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: white;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: white;
}

.step-label {
    font-size: 0.75rem;
    font-weight: 500;
    color: #6c757d;
    white-space: nowrap;
}

.step-item.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

@using sv_61154eade5f549b8920385640ee84344.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input class="form-control @ErrorClass(nameof(Entry.Company))"
                       @bind="Entry.Company" @bind:event="oninput" placeholder="Company name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control @ErrorClass(nameof(Entry.Title))"
                       @bind="Entry.Title" @bind:event="oninput" placeholder="Job title" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control @ErrorClass(nameof(Entry.StartDate))"
                       @bind="Entry.StartDate" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control"
                       @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index"
                           @bind="Entry.IsCurrent" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description <span class="text-danger">*</span></label>
                <textarea class="form-control @ErrorClass(nameof(Entry.Description))" rows="3"
                          @bind="Entry.Description" @bind:event="oninput"
                          placeholder="Describe your responsibilities and achievements"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public HashSet<string> FieldErrors { get; set; } = [];

    private string ErrorClass(string field) =>
        FieldErrors.Contains($"{Index}.{field}") ? "is-invalid" : "";
}

