@using sv_61154eade5f549b8920385640ee84344.Models

<div class="step-content">
    <h4 class="mb-4">Personal Information</h4>

    @if (errors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in errors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input class="form-control @(HasError("FullName") ? "is-invalid" : "")"
                   @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control @(HasError("Email") ? "is-invalid" : "")"
                   @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
            @if (isValidatingEmail)
            {
                <div class="form-text text-info">Validating email...</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control @(HasError("Phone") ? "is-invalid" : "")"
                   @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input class="form-control @(HasError("Address") ? "is-invalid" : "")"
                   @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidatingEmail">
            @if (isValidatingEmail)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Next
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }

    private List<string> errors = [];
    private HashSet<string> errorFields = [];
    private bool isValidatingEmail;

    private bool HasError(string field) => errorFields.Contains(field);

    private async Task HandleNext()
    {
        errors.Clear();
        errorFields.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName)) { errors.Add("Full name is required."); errorFields.Add("FullName"); }
        if (string.IsNullOrWhiteSpace(Model.Email)) { errors.Add("Email is required."); errorFields.Add("Email"); }
        if (string.IsNullOrWhiteSpace(Model.Phone)) { errors.Add("Phone is required."); errorFields.Add("Phone"); }
        if (string.IsNullOrWhiteSpace(Model.Address)) { errors.Add("Address is required."); errorFields.Add("Address"); }

        if (errors.Count > 0) return;

        isValidatingEmail = true;
        StateHasChanged();

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                errors.Add("The email address is not valid.");
                errorFields.Add("Email");
                return;
            }
        }
        finally
        {
            isValidatingEmail = false;
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_61154eade5f549b8920385640ee84344.Models

<div class="step-content">
    <h4 class="mb-4">Work History</h4>

    @if (errors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in errors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryEditor Entry="Entries[index]"
                         Index="index"
                         CanRemove="Entries.Count > 1"
                         FieldErrors="fieldErrors"
                         OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="d-flex justify-content-between mt-2">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private List<string> errors = [];
    private HashSet<string> fieldErrors = [];

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errors.Clear();
        fieldErrors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var e = Entries[i];
            if (string.IsNullOrWhiteSpace(e.Company)) { fieldErrors.Add($"{i}.Company"); }
            if (string.IsNullOrWhiteSpace(e.Title)) { fieldErrors.Add($"{i}.Title"); }
            if (e.StartDate is null) { fieldErrors.Add($"{i}.StartDate"); }
            if (string.IsNullOrWhiteSpace(e.Description)) { fieldErrors.Add($"{i}.Description"); }
        }

        if (fieldErrors.Count > 0)
        {
            errors.Add("Please fill in all required fields for each position.");
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_61154eade5f549b8920385640ee84344.Models

<div class="step-content">
    <h4 class="mb-4">References</h4>
    <p class="text-secondary">Please provide 2–3 professional references.</p>

    @if (errors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in errors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceEditor Ref="References[index]"
                         Index="index"
                         CanRemove="References.Count > 1"
                         FieldErrors="fieldErrors"
                         OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="d-flex justify-content-between mt-2">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private List<string> errors = [];
    private HashSet<string> fieldErrors = [];

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 1)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errors.Clear();
        fieldErrors.Clear();

        for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            if (string.IsNullOrWhiteSpace(r.Name)) { fieldErrors.Add($"{i}.Name"); }
            if (string.IsNullOrWhiteSpace(r.Relationship)) { fieldErrors.Add($"{i}.Relationship"); }
            if (string.IsNullOrWhiteSpace(r.Email)) { fieldErrors.Add($"{i}.Email"); }
            if (string.IsNullOrWhiteSpace(r.Phone)) { fieldErrors.Add($"{i}.Phone"); }
        }

        if (fieldErrors.Count > 0)
        {
            errors.Add("Please fill in all required fields for each reference.");
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_61154eade5f549b8920385640ee84344.Models

<div class="step-content">
    @if (IsSubmitted)
    {
        <div class="text-center py-5">
            <div class="mb-3" style="font-size: 3rem;">✅</div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="text-secondary">Your application has been received.</p>
            <p class="fs-5">Application ID: <strong>#@ApplicationId</strong></p>
        </div>
    }
    else
    {
        <h4 class="mb-4">Review & Submit</h4>
        <p class="text-secondary">Please review your application before submitting.</p>

        @if (!string.IsNullOrEmpty(SubmitError))
        {
            <div class="alert alert-danger">@SubmitError</div>
        }

        <!-- Personal Info -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Personal Information</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                    <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                    <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                    <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
                </div>
            </div>
        </div>

        <!-- Work History -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Work History</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-3 pb-3 border-bottom last-no-border">
                        <div><strong>@entry.Title</strong> at @entry.Company</div>
                        <div class="text-secondary">
                            @entry.StartDate?.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </div>
                        <div class="mt-1">@entry.Description</div>
                    </div>
                }
            </div>
        </div>

        <!-- References -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>References</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
