.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    padding: 1rem 0;
}

.step-connector {
    flex: 1;
    height: 2px;
    background-color: #dee2e6;
    margin: 0 0.25rem;
    max-width: 60px;
    transition: background-color 0.3s;
}

.step-connector.completed {
    background-color: #198754;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0.5rem;
    gap: 0.5rem;
    transition: opacity 0.3s;
}

.step-item.future {
    opacity: 0.4;
    cursor: not-allowed;
}

.step-item.completed:hover .step-circle {
    transform: scale(1.1);
}

.step-circle {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: white;
    color: #6c757d;
    transition: all 0.3s;
}

.step-item.current .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: white;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: white;
}

.step-label {
    font-size: 0.75rem;
    font-weight: 500;
    color: #6c757d;
    white-space: nowrap;
}

.step-item.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

