        <button class="step-item @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                disabled="@isFuture"
                @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
            <div class="step-circle">
                @if (isCompleted)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <span class="step-label">@StepNames[stepIndex]</span>
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public List<string> StepNames { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }
}
"}

