{"path": "/tmp/sv-61154eade5f549b8920385640ee84344/Components/JobApplication/PersonalInfoStep.razor", "file_text": "@using sv_61154eade5f549b8920385640ee84344.Models

<div class="step-content">
    <h4 class="mb-4">Personal Information</h4>

    @if (errors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in errors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input class="form-control @(HasError("FullName") ? "is-invalid" : "")"
                   @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control @(HasError("Email") ? "is-invalid" : "")"
                   @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
            @if (isValidatingEmail)
            {
                <div class="form-text text-info">Validating email...</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control @(HasError("Phone") ? "is-invalid" : "")"
                   @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input class="form-control @(HasError("Address") ? "is-invalid" : "")"
                   @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidatingEmail">
            @if (isValidatingEmail)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Next
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }

    private List<string> errors = [];
    private HashSet<string> errorFields = [];
    private bool isValidatingEmail;

    private bool HasError(string field) => errorFields.Contains(field);

    private async Task HandleNext()
    {
        errors.Clear();
        errorFields.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName)) { errors.Add("Full name is required."); errorFields.Add("FullName"); }
        if (string.IsNullOrWhiteSpace(Model.Email)) { errors.Add("Email is required."); errorFields.Add("Email"); }
        if (string.IsNullOrWhiteSpace(Model.Phone)) { errors.Add("Phone is required."); errorFields.Add("Phone"); }
        if (string.IsNullOrWhiteSpace(Model.Address)) { errors.Add("Address is required."); errorFields.Add("Address"); }

        if (errors.Count > 0) return;

        isValidatingEmail = true;
        StateHasChanged();

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                errors.Add("The email address is not valid.");
                errorFields.Add("Email");
                return;
            }
        }
        finally
        {
            isValidatingEmail = false;
        }

        await OnNext.InvokeAsync();
    }
}
"}

