@using sv_61154eade5f549b8920385640ee84344.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input class="form-control @ErrorClass(nameof(Entry.Company))"
                       @bind="Entry.Company" @bind:event="oninput" placeholder="Company name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control @ErrorClass(nameof(Entry.Title))"
                       @bind="Entry.Title" @bind:event="oninput" placeholder="Job title" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control @ErrorClass(nameof(Entry.StartDate))"
                       @bind="Entry.StartDate" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control"
                       @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index"
                           @bind="Entry.IsCurrent" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description <span class="text-danger">*</span></label>
                <textarea class="form-control @ErrorClass(nameof(Entry.Description))" rows="3"
                          @bind="Entry.Description" @bind:event="oninput"
                          placeholder="Describe your responsibilities and achievements"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public HashSet<string> FieldErrors { get; set; } = [];

    private string ErrorClass(string field) =>
        FieldErrors.Contains($"{Index}.{field}") ? "is-invalid" : "";
}

@using sv_61154eade5f549b8920385640ee84344.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input class="form-control @ErrorClass(nameof(Ref.Name))"
                       @bind="Ref.Name" @bind:event="oninput" placeholder="Reference name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input class="form-control @ErrorClass(nameof(Ref.Relationship))"
                       @bind="Ref.Relationship" @bind:event="oninput" placeholder="e.g., Former Manager" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control @ErrorClass(nameof(Ref.Email))"
                       @bind="Ref.Email" @bind:event="oninput" placeholder="email@example.com" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control @ErrorClass(nameof(Ref.Phone))"
